import type { Meta, StoryObj } from '@storybook/react-vite';
import { Progress } from './Progress';
import { Space } from '../Space';

const meta = {
  title: 'Components/Progress',
  component: Progress,
  tags: ['autodocs'],
  argTypes: {
    percentage: { control: { type: 'range', min: 0, max: 100, step: 1 } },
    type: { control: 'inline-radio', options: ['line', 'circle', 'dashboard'] },
    status: { control: 'inline-radio', options: [undefined, 'success', 'warning', 'exception'] },
    strokeWidth: { control: 'number' },
    showText: { control: 'boolean' },
    textInside: { control: 'boolean' },
    strokeLinecap: { control: 'inline-radio', options: ['round', 'butt', 'square'] },
    width: { control: 'number' },
    indeterminate: { control: 'boolean' },
    duration: { control: 'number' },
    color: { control: false },
    format: { control: false },
  },
  args: {
    percentage: 60,
    type: 'line',
  },
} satisfies Meta<typeof Progress>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => (
    <div style={{ width: 320 }}>
      <Progress {...args} />
    </div>
  ),
};

export const Line: Story = {
  name: 'Line with statuses',
  render: () => (
    <div style={{ display: 'flex', flexDirection: 'column', width: 320, gap: 16 }}>
      <Progress percentage={30} />
      <Progress percentage={70} status="warning" />
      <Progress percentage={100} status="success" />
      <Progress percentage={50} status="exception" />
      <Progress percentage={80} textInside />
    </div>
  ),
};

export const Circle: Story = {
  name: 'Circle and dashboard',
  render: () => (
    <Space wrap style={{ gap: 24 }}>
      <Progress type="circle" percentage={75} />
      <Progress type="circle" percentage={100} status="success" />
      <Progress type="dashboard" percentage={60} />
      <Progress type="dashboard" percentage={40} status="exception" />
    </Space>
  ),
};

export const Indeterminate: Story = {
  render: () => (
    <div style={{ width: 320 }}>
      <Progress percentage={50} indeterminate showText={false} />
    </div>
  ),
};

import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type ProgressType = 'line' | 'circle' | 'dashboard';

export type ProgressStatus = 'success' | 'warning' | 'exception';

export type ProgressColor = string | string[] | ((percentage: number) => string);

export interface ProgressProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'color'> {
  /** Completion percentage, 0–100. */
  percentage: number;
  /** Visual variant. */
  type?: ProgressType;
  /** Stroke thickness in pixels. */
  strokeWidth?: number;
  /** Status, which maps to a color. */
  status?: ProgressStatus;
  /** Custom color: a string, a list (picked by threshold), or a function of the percentage. */
  color?: ProgressColor;
  /** Show the progress text. */
  showText?: boolean;
  /** Render the text inside the bar (line type only). */
  textInside?: boolean;
  /** Shape of the stroke end. */
  strokeLinecap?: 'round' | 'butt' | 'square';
  /** Circle diameter in pixels (circle / dashboard). */
  width?: number;
  /** Animate as an indeterminate bar (line type only). */
  indeterminate?: boolean;
  /** Animation duration in seconds for the indeterminate animation. */
  duration?: number;
  /** Custom text formatter. */
  format?: (percentage: number) => ReactNode;
  children?: ReactNode;
}

const STATUS_COLORS: Record<ProgressStatus, string> = {
  success: 'var(--ec-color-success)',
  warning: 'var(--ec-color-warning)',
  exception: 'var(--ec-color-danger)',
};

/** Pick a stroke color from the color prop, optionally keyed on the percentage. */
function resolveColor(
  color: ProgressColor | undefined,
  status: ProgressStatus | undefined,
  percentage: number,
): string | undefined {
  if (typeof color === 'function') return color(percentage);
  if (Array.isArray(color)) {
    if (color.length === 0) return undefined;
    // Evenly partition the range across the provided colors.
    const span = 100 / color.length;
    const index = Math.min(color.length - 1, Math.floor(percentage / span));
    return color[index];
  }
  if (typeof color === 'string') return color;
  if (status) return STATUS_COLORS[status];
  return undefined;
}

function clamp(value: number): number {
  if (Number.isNaN(value)) return 0;
  return Math.min(100, Math.max(0, value));
}

export const Progress = forwardRef<HTMLDivElement, ProgressProps>(function Progress(props, ref) {
  const {
    percentage,
    type = 'line',
    strokeWidth,
    status,
    color,
    showText = true,
    textInside = false,
    strokeLinecap = 'round',
    width = 126,
    indeterminate = false,
    duration = 3,
    format,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('progress');
  const value = clamp(percentage);
  const isCircle = type === 'circle' || type === 'dashboard';
  const stroke = strokeWidth ?? (isCircle ? 8 : 6);
  const strokeColor = resolveColor(color, status, value);

  const classes = cls(
    ns.b(),
    ns.m(type),
    status && ns.is(status),
    ns.is('text-inside', textInside),
    ns.is('indeterminate', indeterminate),
    className,
  );

  const text: ReactNode = format ? format(value) : `${value}%`;

  const ariaProps = {
    role: 'progressbar',
    'aria-valuenow': value,
    'aria-valuemin': 0,
    'aria-valuemax': 100,
  } as const;

  if (!isCircle) {
    const barStyle: CSSProperties = { width: `${value}%` };
    if (strokeColor) barStyle.backgroundColor = strokeColor;
    if (indeterminate) barStyle.animationDuration = `${duration}s`;

    return (
      <div ref={ref} className={classes} {...ariaProps} {...rest}>
        <div className={ns.e('bar')}>
          <div className={ns.e('outer')} style={{ height: stroke }}>
            <div className={ns.e('inner')} style={barStyle}>
              {showText && textInside && (
                <span className={ns.e('innerText')}>{text}</span>
              )}
            </div>
          </div>
        </div>
        {showText && !textInside && <span className={ns.e('text')}>{text}</span>}
        {children}
      </div>
    );
  }

  // --- Circle / dashboard geometry ---
  const radius = 50 - stroke / 2;
  const circumference = 2 * Math.PI * radius;
  // Dashboard leaves a 75% gap at the bottom; circle is a full ring.
  const isDashboard = type === 'dashboard';
  const rate = isDashboard ? 0.75 : 1;
  const trackLength = circumference * rate;

  // Rotate so the dashboard opening sits at the bottom and circle starts at top.
  const rotation = isDashboard ? 90 + (1 - rate) * 360 * 0.5 : -90;

  const trackPath = (
    <path
      className={ns.e('circle-track')}
      d={describeArc(radius)}
      fill="none"
      strokeWidth={stroke}
      style={{
        strokeDasharray: `${trackLength}px ${circumference}px`,
        strokeDashoffset: 0,
      }}
    />
  );

  const progressDash = (value / 100) * trackLength;
  const pathStyle: CSSProperties = {
    strokeDasharray: `${progressDash}px ${circumference}px`,
    strokeDashoffset: 0,
    transition: 'stroke-dasharray 0.6s ease 0s, stroke 0.6s ease',
  };
  if (strokeColor) pathStyle.stroke = strokeColor;

  return (
    <div ref={ref} className={classes} {...ariaProps} {...rest}>
      <div className={ns.e('circle')} style={{ width, height: width }}>
        <svg viewBox="0 0 100 100" width="100%" height="100%">
          <g transform={`rotate(${rotation} 50 50)`}>
            {trackPath}
            <path
              className={ns.e('circle-path')}
              d={describeArc(radius)}
              fill="none"
              strokeWidth={stroke}
              strokeLinecap={strokeLinecap}
              style={pathStyle}
            />
          </g>
        </svg>
        {showText && <span className={ns.e('text')}>{text}</span>}
      </div>
      {children}
    </div>
  );
});

/** A near-closed circular arc centered in the 100x100 viewBox, drawn from the top. */
function describeArc(radius: number): string {
  return [
    `M 50 50`,
    `m 0 -${radius}`,
    `a ${radius} ${radius} 0 1 1 0 ${radius * 2}`,
    `a ${radius} ${radius} 0 1 1 0 -${radius * 2}`,
  ].join(' ');
}

.ec-progress {
  --ec-progress-fill-color: var(--ec-color-primary);
  --ec-progress-track-color: var(--ec-fill-color-light);
  --ec-progress-text-color: var(--ec-text-color-regular);
  --ec-progress-inner-text-color: var(--ec-color-white);
  --ec-progress-radius: var(--ec-border-radius-round);

  box-sizing: border-box;
  font-family: inherit;
  line-height: 1;
}

/* ---- Line ---- */
.ec-progress--line {
  display: flex;
  align-items: center;
}

.ec-progress__bar {
  flex: 1;
  box-sizing: border-box;
  margin-right: 0;
}

.ec-progress--line:not(.is-text-inside) .ec-progress__bar {
  margin-right: 6px;
}

.ec-progress__outer {
  position: relative;
  box-sizing: border-box;
  width: 100%;
  overflow: hidden;
  background-color: var(--ec-progress-track-color);
  border-radius: var(--ec-progress-radius);
}

.ec-progress__inner {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  box-sizing: border-box;
  height: 100%;
  background-color: var(--ec-progress-fill-color);
  border-radius: var(--ec-progress-radius);
  transition: width 0.6s ease, background-color 0.6s ease;
}

.ec-progress__innerText {
  display: inline-block;
  margin: 0 5px;
  font-size: 12px;
  color: var(--ec-progress-inner-text-color);
  vertical-align: middle;
}

.ec-progress__text {
  display: inline-block;
  min-width: 50px;
  font-size: var(--ec-font-size-base);
  line-height: 1;
  color: var(--ec-progress-text-color);
  white-space: nowrap;
}

/* ---- Status colors (line + circle share the fill var) ---- */
.ec-progress.is-success {
  --ec-progress-fill-color: var(--ec-color-success);
}
.ec-progress.is-warning {
  --ec-progress-fill-color: var(--ec-color-warning);
}
.ec-progress.is-exception {
  --ec-progress-fill-color: var(--ec-color-danger);
}

/* ---- Indeterminate (line only) ---- */
.ec-progress.is-indeterminate .ec-progress__inner {
  width: 100% !important;
  animation: ec-progress-indeterminate 3s infinite ease;
  transform-origin: left center;
}

@keyframes ec-progress-indeterminate {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(100%);
  }
}

/* ---- Circle / dashboard ---- */
.ec-progress--circle,
.ec-progress--dashboard {
  display: inline-block;
}

.ec-progress__circle {
  position: relative;
  display: inline-block;
}

.ec-progress__circle-track {
  stroke: var(--ec-progress-track-color);
}

.ec-progress__circle-path {
  stroke: var(--ec-progress-fill-color);
}

.ec-progress--circle .ec-progress__text,
.ec-progress--dashboard .ec-progress__text {
  position: absolute;
  top: 50%;
  left: 0;
  width: 100%;
  margin: 0;
  text-align: center;
  transform: translateY(-50%);
  font-size: var(--ec-font-size-large);
  color: var(--ec-progress-text-color);
}
